// Solution
var css = require('css');
function parseCss(cssString) {
  var stylesheet = css.parse(cssString);
  var result = {};
  // Iterate over the CSS rules
  stylesheet.stylesheet.rules.forEach(function(rule) {
    // Check if the rule is a pseudo-element rule
    if (rule.type === 'rule') {
      // Get the selector and styles of the rule
      var selector = rule.selectors[0];
      var styles = rule.declarations;
      // Add the rule to the result object
      if (selector.includes('::before') || selector.includes('::after')) {
        result[selector] = {};
        for (var i = 0; i < styles.length; i++) {
          result[selector][styles[i].property] = styles[i].value;
        }
      }
    }
  });
  return result;
}

// Call the function with a test CSS string
var result = parseCss('.class::before { content: 'Hello'; }');
console.log(result);

